import React, { useState, useEffect } from "react";
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  Divider,
  Alert,
  CircularProgress,
  Grid,
} from "@mui/material";
import { useAuth } from "../../context/AuthContext";
import { useNavigate } from "react-router-dom";
import {
  validateSignatureFile,
  compressSignatureImage,
} from "../../utils/signatureUtils";
import userService from "../../services/userService";

const Profile = () => {
  const { currentUser, updateUser, logout, refreshCurrentUser } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [signatureLoading, setSignatureLoading] = useState(false);
  const [success, setSuccess] = useState("");
  const [signatureSuccess, setSignatureSuccess] = useState("");
  const [error, setError] = useState("");
  const [formData, setFormData] = useState({
    phone: "",
    password: "",
    confirmPassword: "",
  });

  // Initialize form data when currentUser first loads
  useEffect(() => {
    if (currentUser && currentUser.phone !== undefined) {
      setFormData((prev) => ({
        ...prev,
        phone: currentUser.phone || "",
      }));
    }
  }, [currentUser?.phone]);

  // Refresh current user data when profile page loads to ensure latest signature is displayed
  useEffect(() => {
    if (currentUser?._id) {
      refreshCurrentUser();
    }
  }, [currentUser?._id, refreshCurrentUser]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSignatureUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    try {
      setSignatureLoading(true);
      setError("");
      setSignatureSuccess("");

      // Validate the file
      const validationResult = await validateSignatureFile(file);
      if (!validationResult.isValid) {
        setError(validationResult.error);
        return;
      }

      // Convert file to data URL first
      const reader = new FileReader();
      const dataUrl = await new Promise((resolve, reject) => {
        reader.onload = () => resolve(reader.result);
        reader.onerror = reject;
        reader.readAsDataURL(file);
      });

      // Compress the image
      const compressedImage = await compressSignatureImage(dataUrl);

      // Update user signature using userService to ensure consistency with user management pages
      await userService.update(currentUser._id, { signature: compressedImage });

      // Refresh the current user data to ensure consistency across the application
      await refreshCurrentUser();

      setSignatureSuccess("Signature updated successfully");

      // Clear the file input
      e.target.value = "";

      // Clear success message after 5 seconds
      setTimeout(() => {
        setSignatureSuccess("");
      }, 5000);
    } catch (error) {
      console.error("Error processing signature:", error);
      setError("Error processing signature image");
    } finally {
      setSignatureLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    setSuccess("");
    setSignatureSuccess("");

    try {
      // Validate password if it's being changed
      if (formData.password) {
        if (formData.password !== formData.confirmPassword) {
          throw new Error("Passwords do not match");
        }
        if (formData.password.length < 6) {
          throw new Error("Password must be at least 6 characters long");
        }
        // Add password complexity validation
        const hasUpperCase = /[A-Z]/.test(formData.password);
        const hasLowerCase = /[a-z]/.test(formData.password);
        const hasNumbers = /\d/.test(formData.password);
        const hasSpecialChar = /[!@#$%^&*(),.?":{}|<>]/.test(formData.password);

        if (!hasUpperCase || !hasLowerCase || !hasNumbers || !hasSpecialChar) {
          throw new Error(
            "Password must contain at least one uppercase letter, one lowercase letter, one number, and one special character"
          );
        }
      }

      // Update user data
      const updatedUser = {
        ...currentUser,
        phone: formData.phone.trim() || "",
      };

      if (formData.password) {
        updatedUser.password = formData.password;
      }

      await updateUser(updatedUser);
      setSuccess("Profile updated successfully");
      // Clear password fields after successful update
      setFormData((prev) => ({ ...prev, password: "", confirmPassword: "" }));
    } catch (err) {
      setError(err.message || "Failed to update profile");
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <Box
      sx={{
        maxWidth: 800,
        mx: "auto",
        p: 3,
      }}
    >
      <Paper
        elevation={3}
        sx={{
          p: 4,
          borderRadius: 2,
        }}
      >
        <Typography variant="h4" gutterBottom color="black">
          Profile Settings
        </Typography>

        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {success && (
          <Alert severity="success" sx={{ mb: 2 }}>
            {success}
          </Alert>
        )}

        {signatureSuccess && (
          <Alert severity="success" sx={{ mb: 2 }}>
            {signatureSuccess}
          </Alert>
        )}

        <form onSubmit={handleSubmit}>
          <Grid container spacing={3}>
            {/* Profile Information Section */}
            <Grid item xs={12}>
              <Typography variant="h6" gutterBottom color="black">
                Profile Information
              </Typography>
            </Grid>

            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Email"
                value={currentUser?.email || ""}
                disabled
                variant="outlined"
              />
            </Grid>

            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Phone"
                name="phone"
                value={formData.phone || ""}
                onChange={handleChange}
                variant="outlined"
                autoComplete="tel"
              />
            </Grid>
            <Divider sx={{ my: 3 }} />
            {/* Password Section */}
            <Grid item xs={12}>
              <Typography variant="h6" gutterBottom color="black">
                Change Password
              </Typography>
            </Grid>

            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                label="New Password"
                name="password"
                type="password"
                value={formData.password}
                onChange={handleChange}
                variant="outlined"
                autoComplete="new-password"
              />
            </Grid>

            <Grid item xs={12} sm={6}>
              <TextField
                fullWidth
                label="Confirm New Password"
                name="confirmPassword"
                type="password"
                value={formData.confirmPassword}
                onChange={handleChange}
                variant="outlined"
                autoComplete="new-password"
              />
            </Grid>

            <Grid item xs={12}>
              <Button
                type="submit"
                variant="contained"
                color="primary"
                disabled={loading}
                sx={{ mr: 2 }}
              >
                {loading ? <CircularProgress size={24} /> : "Save Changes"}
              </Button>
            </Grid>

            <Grid item xs={12}>
              <Divider sx={{ my: 3 }} />
            </Grid>

            {/* Signature Upload Section */}
            <Grid item xs={12}>
              <Typography variant="h6" gutterBottom color="black">
                Signature
              </Typography>
              <Typography variant="body2" color="textSecondary" sx={{ mb: 2 }}>
                Upload your signature for use in reports and documents
              </Typography>

              <input
                accept="image/*"
                style={{ display: "none" }}
                id="signature-upload"
                type="file"
                onChange={handleSignatureUpload}
              />
              <label htmlFor="signature-upload">
                <Button
                  variant="outlined"
                  component="span"
                  disabled={signatureLoading}
                  sx={{ mb: 2 }}
                >
                  {signatureLoading ? (
                    <CircularProgress size={20} />
                  ) : currentUser?.signature ? (
                    "Replace Signature"
                  ) : (
                    "Upload Signature"
                  )}
                </Button>
              </label>

              {currentUser?.signature && (
                <Box sx={{ mt: 2 }}>
                  <Typography variant="body2" sx={{ mb: 1 }}>
                    Current Signature:
                  </Typography>
                  <Box
                    component="img"
                    src={currentUser.signature}
                    alt="Signature preview"
                    sx={{
                      maxWidth: 200,
                      maxHeight: 100,
                      border: "1px solid #ddd",
                      borderRadius: 1,
                    }}
                  />
                </Box>
              )}
            </Grid>

            <Grid item xs={12}>
              <Divider sx={{ my: 3 }} />
            </Grid>

            {/* Logout Section */}
            <Grid item xs={12}>
              <Box sx={{ display: "flex", justifyContent: "center", mt: 2 }}>
                <Button
                  variant="contained"
                  color="error"
                  onClick={handleLogout}
                  size="large"
                  sx={{
                    minWidth: 200,
                    py: 1.5,
                    fontSize: "1.1rem",
                  }}
                >
                  Logout
                </Button>
              </Box>
            </Grid>
          </Grid>
        </form>
      </Paper>
    </Box>
  );
};

export default Profile;
